<!DOCTYPE html>
<html lang='nl'>
<head>
    <meta charset='UTF-8'>
    <title>Ontsleuteld Bestand</title>
</head>
<body>

    <h1>Ontsleutelde Afbeelding:</h1>
    <img src='data:image/jpeg;base64,' alt='Ontsleuteld' style='max-width:100%; height:auto;'><br><br>
    <p>Als het goed is, is de download ook automatisch gestart.</p>

    <script>
    window.addEventListener('DOMContentLoaded', () => {
        const link = document.createElement('a');
        link.href = 'data:image/jpeg;base64,';
        link.download = 'gedownload_bestand.jpg';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    });
    </script>

</body>
</html>